// Extract actionable suggestions from CodeRabbit/DeepSource comments
const items = $input.all();
const suggestions = [];

for (const item of items) {
  const body = item.json.body || '';
  const author = item.json.user?.login || 'unknown';
  const path = item.json.path || 'unknown';
  const line = item.json.original_line || item.json.line || 0;

  // Extract code suggestions (```suggestion blocks)
  const suggestionRegex = /```suggestion\n([\s\S]*?)```/g;
  let match;
  while ((match = suggestionRegex.exec(body)) !== null) {
    suggestions.push({
      author,
      path,
      line,
      suggestion: match[1].trim(),
      type: 'code_suggestion',
      autoFixable: true
    });
  }

  // Extract general comments (non-code)
  if (!suggestionRegex.test(body) && body.length > 10) {
    suggestions.push({
      author,
      path,
      line,
      suggestion: body.substring(0, 500),
      type: 'comment',
      autoFixable: false
    });
  }
}

const autoFixable = suggestions.filter(s => s.autoFixable);
const manualReview = suggestions.filter(s => !s.autoFixable);

return [{
  json: {
    totalSuggestions: suggestions.length,
    autoFixableCount: autoFixable.length,
    manualReviewCount: manualReview.length,
    autoFixable,
    manualReview,
    timestamp: new Date().toISOString()
  }
}];

