const nacl = require('tweetnacl');

const headers = $node["Webhook"].json.headers;
const signature = headers['x-signature-ed25519'];
const timestamp = headers['x-signature-timestamp'];
const body = $node["Webhook"].json.body;

// Discord requires raw body string for verification
const rawBody = JSON.stringify(body);

const publicKey = 'e62778c8ab22009d2149d75eb77b1c3b2dc44a22aee4e1817201a6c6ecf59994';

try {
  const isVerified = nacl.sign.detached.verify(
    Buffer.from(timestamp + rawBody),
    Buffer.from(signature, 'hex'),
    Buffer.from(publicKey, 'hex')
  );

  if (!isVerified) {
    throw new Error('Invalid signature');
  }
} catch (err) {
  return { 
    error: 'Verification failed', 
    detail: err.message 
  };
}

return body;
